const observerOptions={root:null,rootMargin:"0px",threshold:.1},observerCallback=(entries,observer)=>{entries.forEach(entry=>{entry.isIntersecting&&(entry.target.classList.add("in-frame"),observer.unobserve(entry.target))})},observer=new IntersectionObserver(observerCallback,observerOptions),hiddenElements=document.querySelectorAll(".animate-on-scroll");hiddenElements.forEach(el=>observer.observe(el));